import React, { useState } from "react";
import axios from "axios";
import { Section } from "./Section";
import { Toaster, toast } from "sonner";

const API = `${process.env.REACT_APP_BACKEND_URL}/api`;

const initial = {
  name: "",
  email: "",
  phone: "",
  address: "",
  work_type: "",
  experience: "",
  message: "",
};

export default function WorkerForm() {
  const [form, setForm] = useState(initial);
  const [loading, setLoading] = useState(false);

  const onChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value,
    });
  };

  const onSubmit = async (e) => {
    e.preventDefault();

    try {
      setLoading(true);

      await axios.post(
        `${API}/worker-registration`,
        form
      );

      toast.success(
        "Registration submitted successfully."
      );

      setForm(initial);
    } catch (err) {
      toast.error(
        "Could not submit registration."
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <Section
      id="workers"
      className="bg-[#111111] text-white"
    >
      <Toaster richColors />

      <div className="max-w-4xl mx-auto">
        <h2 className="font-serif text-5xl mb-4">
          Join As Worker
        </h2>

        <p className="text-white/70 mb-10">
          Painter, Plumber, Electrician,
          False Ceiling, Tiles Work,
          Carpenter and other professionals
          can register here.
        </p>

        <form
          onSubmit={onSubmit}
          className="space-y-6"
        >
          <input
            name="name"
            placeholder="Full Name"
            value={form.name}
            onChange={onChange}
            className="w-full p-4 bg-transparent border"
            required
          />

          <input
            name="email"
            type="email"
            placeholder="Email"
            value={form.email}
            onChange={onChange}
            className="w-full p-4 bg-transparent border"
            required
          />

          <input
            name="phone"
            placeholder="Phone Number"
            value={form.phone}
            onChange={onChange}
            className="w-full p-4 bg-transparent border"
            required
          />

          <input
            name="address"
            placeholder="Address"
            value={form.address}
            onChange={onChange}
            className="w-full p-4 bg-transparent border"
          />

          <select
            name="work_type"
            value={form.work_type}
            onChange={onChange}
            className="w-full p-4 bg-black border"
            required
          >
            <option value="">
              Select Work Type
            </option>

            <option>Painter</option>
            <option>Plumber</option>
            <option>Electrician</option>
            <option>False Ceiling</option>
            <option>Tiles Work</option>
            <option>Carpenter</option>
            <option>POP Work</option>
            <option>Welder</option>
            <option>Interior Contractor</option>
            <option>Modular Kitchen Installer</option>
            <option>Other</option>
          </select>

          <input
            name="experience"
            placeholder="Experience (e.g. 5 years)"
            value={form.experience}
            onChange={onChange}
            className="w-full p-4 bg-transparent border"
          />

          <textarea
            rows={4}
            name="message"
            placeholder="Tell us about your work"
            value={form.message}
            onChange={onChange}
            className="w-full p-4 bg-transparent border"
          />

          <button
            type="submit"
            disabled={loading}
            className="bg-[#D4AF37] px-10 py-4 text-black font-semibold"
          >
            {loading
              ? "Submitting..."
              : "Register Now"}
          </button>
        </form>
      </div>
    </Section>
  );
}
